DROP DATABASE IF EXISTS tour_gwangju;

CREATE DATABASE tour_gwangju
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

USE tour_gwangju;
DROP TABLE IF EXISTS places_unique;
CREATE TABLE places_unique (
  place_id INT PRIMARY KEY,
  line_name VARCHAR(30),
  station_name VARCHAR(80),
  station_code VARCHAR(30),
  station_district VARCHAR(30),
  station_latitude DECIMAL(10,7),
  station_longitude DECIMAL(10,7),
  place_name VARCHAR(200),
  category VARCHAR(80),
  place_type VARCHAR(80),
  address VARCHAR(255),
  phone VARCHAR(80),
  district VARCHAR(30),
  theme_tags VARCHAR(255),
  date_score TINYINT,
  source_grade VARCHAR(100),
  source_basis TEXT,
  source_file VARCHAR(255),
  source_url TEXT,
  accuracy_score TINYINT,
  match_status VARCHAR(100),
  kakao_search_keyword VARCHAR(255),
  kakao_category_group_code VARCHAR(20),
  naver_place_search_url TEXT,
  kakao_place_search_url TEXT,
  naver_review_count_min INT NULL,
  naver_rating_min DECIMAL(2,1) NULL,
  image_url TEXT,
  latitude DECIMAL(10,7) NULL,
  longitude DECIMAL(10,7) NULL,
  map_verify_status VARCHAR(120),
  station_area_key VARCHAR(80)
) DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE INDEX idx_integrated_station ON  places_unique(line_name, station_name);
CREATE INDEX idx_integrated_category ON  places_unique(category);

